use anyhow::{anyhow, Result};

fn process_data(input: &str) -> Result<String> {
    if input.is_empty() {
        return Err(anyhow!("Input cannot be empty"));
    }
    Ok(input.to_uppercase())
}

pub trait Handler<T> {
    fn handle(&mut self, item: T) -> anyhow::Result<()>;
}

pub struct MyHandler;

impl Handler<String> for MyHandler {
    fn handle(&mut self, item: String) -> anyhow::Result<()> {
        println!("Handling: {}", item);
        Ok(())
    }
}

use tokio::sync::mpsc;

pub struct EventBus {
    tx: mpsc::Sender<String>,
    rx: mpsc::Receiver<String>,
}

impl EventBus {
    pub fn new(capacity: usize) -> Self {
        let (tx, rx) = mpsc::channel(capacity);
        Self { tx, rx }
    }
}

use std::collections::VecDeque;

pub struct MessageQueue {
    messages: VecDeque<String>,
}

impl MessageQueue {
    pub fn new() -> Self {
        Self { messages: VecDeque::new() }
    }

    pub fn push(&mut self, msg: String) {
        self.messages.push_back(msg);
    }

    pub fn pop(&mut self) -> Option<String> {
        self.messages.pop_front()
    }
}

use std::sync::Arc;
use tokio::sync::Mutex;

type SharedState<T> = Arc<Mutex<T>>;

async fn use_shared_state(state: SharedState<String>) {
    let mut locked = state.lock().await;
    locked.push_str(" appended");
}

fn divide(a: i32, b: i32) -> Result<i32, String> {
    if b == 0 {
        Err("Division by zero".to_string())
    } else {
        Ok(a / b)
    }
}

fn main() {
    match divide(10, 2) {
        Ok(result) => println!("Result: {}", result),
