    }
}

#[derive(Debug, Clone)]
pub enum Command {
    LoadPdf(std::path::PathBuf),
    RunShell(String),
    Chat(String),
    Quit,
    Help,
}

impl Command {
    pub fn parse(input: &str) -> Self {
        if input.starts_with(":load ") {
            Command::LoadPdf(std::path::PathBuf::from(&input[6..]))
        } else if input.starts_with(":run ") {
            Command::RunShell(input[5..].to_string())
        } else {
            Command::Chat(input.to_string())
        }
    }
}
